// Código para n8n - Analisador de Horários Livres
// Este código deve ser usado em um nó "Code" do n8n
// IMPORTANTE: Use um nó "Aggregate" antes deste código para juntar todos os eventos

// ========== CONFIGURAÇÕES - ALTERE AQUI ==========
const WORKING_HOURS = {
  start: 9, // Horário de início (9:00)
  end: 18,  // Horário de fim (18:00)
};

const SLOT_DURATION = 60; // Duração de cada slot em minutos

const DAYS_TO_CHECK = 14; // Quantos dias verificar à frente

const TIMEZONE = 'America/Sao_Paulo'; // Fuso horário
// ===============================================

// Função principal
function findFreeSlots() {
  // Pega os dados agregados do calendário
  // O aggregate junta todos os eventos em um único array
  const inputData = $input.first().json.data;

  // Debug: vamos ver como os dados estão chegando
  console.log('Input data structure:', Object.keys(inputData));
  console.log('Full input:', JSON.stringify(inputData, null, 2));

  // Tenta diferentes estruturas possíveis do aggregate
  let calendarData = [];

  if (inputData.data && Array.isArray(inputData.data)) {
    calendarData = inputData.data;
  } else if (Array.isArray(inputData)) {
    calendarData = inputData;
  } else if (inputData.items && Array.isArray(inputData.items)) {
    calendarData = inputData.items;
  } else {
    // Se não encontrar, procura por arrays dentro do objeto
    for (const key in inputData) {
      if (Array.isArray(inputData[key]) && inputData[key].length > 0) {
        calendarData = inputData[key];
        break;
      }
    }
  }

  console.log('Calendar data found:', calendarData.length, 'events');
  console.log('First event sample:', calendarData[0]);

  // Gera os próximos X dias, começando de amanhã
  const today = new Date();
  const nextDays = [];

  // O loop começa com i = 1 para pular o dia de hoje
  for (let i = 1; i < DAYS_TO_CHECK + 1; i++) {
    const date = new Date(today);
    date.setDate(today.getDate() + i);
    nextDays.push(date);
  }

  const freeSlots = [];

  // Para cada dia
  nextDays.forEach(date => {
    const dayString = date.toISOString().split('T')[0];

    // Pula fins de semana (opcional - remova se quiser incluir)
    const dayOfWeek = date.getDay();
    if (dayOfWeek === 0 || dayOfWeek === 6) {
      return; // Pula domingo (0) e sábado (6)
    }

    // Busca eventos do dia
    const dayEvents = calendarData.filter(event => {
      if (!event.start) return false;

      const eventDate = event.start.date || event.start.dateTime?.split('T')[0];
      return eventDate === dayString;
    });

    // Gera slots do horário comercial
    const daySlots = generateDaySlots(date, dayEvents);
    freeSlots.push(...daySlots);
  });

  return freeSlots;
}

// Gera slots para um dia específico
function generateDaySlots(date, dayEvents) {
  const slots = [];
  const dayString = date.toISOString().split('T')[0];

  // Converte eventos para array de períodos ocupados
  const busyPeriods = dayEvents.map(event => {
    let startTime, endTime;

    if (event.start.dateTime) {
      // Evento com horário específico
      startTime = new Date(event.start.dateTime);
      endTime = new Date(event.end.dateTime);
    } else if (event.start.date) {
      // Evento de dia inteiro
      const eventDate = new Date(event.start.date + 'T00:00:00');
      if (event.summary === 'off' || event.summary === 'close') {
        // Se for "off" ou "close", considera como indisponível
        startTime = new Date(eventDate);
        startTime.setHours(0, 0, 0, 0);
        endTime = new Date(eventDate);
        endTime.setHours(23, 59, 59, 999);
      } else {
        return null; // Ignora outros eventos de dia inteiro
      }
    }

    return startTime && endTime ? { start: startTime, end: endTime } : null;
  }).filter(period => period !== null);

  // Ordena períodos ocupados por horário de início
  busyPeriods.sort((a, b) => a.start - b.start);

  // Gera slots livres
  let currentTime = new Date(date);
  currentTime.setHours(WORKING_HOURS.start, 0, 0, 0);

  const endOfDay = new Date(date);
  endOfDay.setHours(WORKING_HOURS.end, 0, 0, 0);

  while (currentTime < endOfDay) {
    const slotEnd = new Date(currentTime);
    slotEnd.setMinutes(slotEnd.getMinutes() + SLOT_DURATION);

    // Verifica se o slot está livre
    const isFree = !busyPeriods.some(period => {
      return (currentTime < period.end && slotEnd > period.start);
    });

    if (isFree && slotEnd <= endOfDay) {
      slots.push({
        date: dayString,
        start: formatTime(currentTime),
        end: formatTime(slotEnd),
        startDateTime: currentTime.toISOString(),
        endDateTime: slotEnd.toISOString(),
        duration: SLOT_DURATION,
        dayOfWeek: getDayName(currentTime.getDay())
      });
    }

    // Avança para o próximo slot
    currentTime.setMinutes(currentTime.getMinutes() + SLOT_DURATION);
  }

  return slots;
}

// Funções auxiliares
function formatTime(date) {
  return date.toLocaleTimeString('pt-BR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: TIMEZONE
  });
}

function getDayName(dayIndex) {
  const days = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];
  return days[dayIndex];
}

// Executa a análise
const freeSlots = findFreeSlots();

// Verifica se há horários livres
if (freeSlots.length === 0) {
  return {
    message: `Não há horários livres nos próximos ${DAYS_TO_CHECK} dias`,
    freeSlots: [],
    totalSlots: 0,
    summary: {
      totalDays: DAYS_TO_CHECK,
      workingDays: 0,
      slotsPerDay: {}
    }
  };
}

// Retorna resultado no formato esperado pelo n8n
return {
  freeSlots: freeSlots,
  totalSlots: freeSlots.length,
  summary: {
    totalDays: DAYS_TO_CHECK,
    workingDays: freeSlots.reduce((acc, slot) => {
      const dates = acc.filter(d => d === slot.date);
      return dates.length === 0 ? [...acc, slot.date] : acc;
    }, []).length,
    slotsPerDay: freeSlots.reduce((acc, slot) => {
      acc[slot.date] = (acc[slot.date] || 0) + 1;
      return acc;
    }, {})
  }
};

// O código espera receber um array de 'freeSlots'
const freeSlots = $input.all().map(item => item.json.freeSlots).flat();

if (!freeSlots || freeSlots.length === 0) {
  return [{ json: { message: 'Nenhum horário livre encontrado para formatar.' } }];
}

// Objeto para agrupar os horários por data
const groupedSlots = {};

freeSlots.forEach(slot => {
  const dateKey = slot.date;

  if (!groupedSlots[dateKey]) {
    groupedSlots[dateKey] = {
      date: dateKey,
      dayOfWeek: slot.dayOfWeek,
      times: []
    };
  }

  groupedSlots[dateKey].times.push(`${slot.start} às ${slot.end}`);
});

// Converte o objeto agrupado em um array de objetos formatados para a IA
const outputForAI = Object.values(groupedSlots).map(day => {
  // Converte a data de 'YYYY-MM-DD' para 'Dia <Dia> de <Mês>'
  const dateParts = day.date.split('-');
  const date = new Date(dateParts[0], dateParts[1] - 1, dateParts[2]);

  const options = { day: 'numeric', month: 'long' };
  const formattedDate = date.toLocaleDateString('pt-BR', options);

  // Formato final para a IA
  return {
    dia: formattedDate,
    diaSemana: day.dayOfWeek,
    horariosDisponiveis: day.times
  };
});

// A saída do nó será um array de objetos JSON
return outputForAI.map(item => ({ json: item }));

